SELECT ,
       e.enterprise_name AS enterprise_name,
       u.real_name AS assignee_name
FROM aw_audit_task t
LEFT JOIN ent_enterprise e ON e.id = t.enterprise_id AND e.deleted = 0
LEFT JOIN sys_user u ON u.id = t.assignee_id AND u.deleted = 0
WHERE t.deleted = 0

    AND t.enterprise_id = #{enterpriseId}


    AND t.audit_year = #{auditYear}


    AND t.status = #{status}


    AND t.assignee_id = #{assigneeId}


    AND t.task_type = #{taskType}

ORDER BY t.create_time DESC

SELECT , e.enterprise_name AS enterprise_name, u.real_name AS assignee_name FROM aw_audit_task t LEFT JOIN ent_enterprise e ON e.id = t.enterprise_id AND e.deleted = 0 LEFT JOIN sys_user u ON u.id = t.assignee_id AND u.deleted = 0 WHERE t.deleted = 0 AND t.assignee_id = #{assigneeId}
AND t.status = #{status}
ORDER BY t.create_time DESC

SELECT COUNT(*) FROM aw_audit_task
WHERE deleted = 0

    AND assignee_id = #{assigneeId}


    AND status = #{status}
